import ast
import os

def load_data(data_var):
    if isinstance(data_var, str) and os.path.isfile(data_var):
        with open(data_var, 'r') as f:
            return json.load(f)
    return data_var

reviewed_list = load_data(locals()['var_function-call-5883064184166049203'])
business_list = load_data(locals()['var_function-call-5947695204761618617'])

# 1. Get IDs of businesses reviewed in 2018
reviewed_ids = set()
for item in reviewed_list:
    # business_ref format: "businessref_123"
    ref = item.get('business_ref')
    if ref and ref.startswith('businessref_'):
        try:
            # Extract ID part to match
            bid = ref.split('_')[1]
            reviewed_ids.add(bid)
        except IndexError:
            pass

# 2. Get IDs of businesses with parking (Bike or Business)
parking_ids = set()
for item in business_list:
    # business_id format: "businessid_123"
    bid_raw = item.get('business_id')
    if not bid_raw or not bid_raw.startswith('businessid_'):
        continue

    bid = bid_raw.split('_')[1]
    attrs = item.get('attributes')

    # Attributes can be None, "None", or a dict
    if attrs is None or attrs == "None":
        continue

    if not isinstance(attrs, dict):
        continue

    has_parking = False

    # Check BikeParking
    # It is usually a string "True" or "False"
    bike_parking = attrs.get('BikeParking')
    if bike_parking == 'True':
        has_parking = True

    # Check BusinessParking
    # It is usually a string representation of a dict: "{'garage': False, ...}"
    if not has_parking:
        bus_parking = attrs.get('BusinessParking')
        if bus_parking and isinstance(bus_parking, str) and bus_parking != 'None':
            try:
                bp_dict = ast.literal_eval(bus_parking)
                if isinstance(bp_dict, dict):
                    # If any value is True, they have parking
                    if any(bp_dict.values()):
                        has_parking = True
            except (ValueError, SyntaxError):
                pass

    if has_parking:
        parking_ids.add(bid)

# 3. Intersect
result_ids = reviewed_ids.intersection(parking_ids)

print("__RESULT__:")
print(json.dumps(len(result_ids)))"}

